import React, { useState, useEffect, useMemo } from 'react';
// ... (tus otros imports de lucide-react)
import { Calendar, Send, Check } from 'lucide-react';

const GestionOfertas = () => {
  // ... (tus estados actuales)
  const [fechasPublicacion, setFechasPublicacion] = useState({ inicio: '', fin: '' });
  const [publishing, setPublishing] = useState(false);

  // Filtramos cuántos productos están "pendientes" de publicar
  const pendientes = useMemo(() => ofertas.filter(o => !o.publicado).length, [ofertas]);

  const handlePublicarTodo = async () => {
    if (!fechasPublicacion.inicio || !fechasPublicacion.fin) {
      return alert("Por favor, selecciona las fechas de vigencia de la oferta.");
    }
    
    setPublishing(true);
    try {
      await axios.put(`${API_URL}/api/ofertas/publicar-todo/${localId}`, {
        fechaInicio: fechasPublicacion.inicio,
        fechaFin: fechasPublicacion.fin
      });
      alert("¡Ofertas publicadas con éxito!");
      cargarOfertas(); // Recargar la lista
    } catch (e) {
      alert("Error al publicar");
    } finally {
      setPublishing(false);
    }
  };

  return (
    <div style={containerStyle}>
      {/* ... (Barra superior y Stats) */}

      <GestionInventario localId={localId} onComplete={cargarOfertas} />

      {/* BARRA DE PUBLICACIÓN MASIVA (Solo aparece si hay productos cargados no publicados) */}
      {pendientes > 0 && (
        <div style={publishBannerStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <div style={pendingBadge}>{pendientes} productos listos</div>
            <div style={inputDateGroup}>
              <label style={labelDate}>Desde:</label>
              <input 
                type="date" 
                style={dateInput} 
                onChange={(e) => setFechasPublicacion({...fechasPublicacion, inicio: e.target.value})}
              />
            </div>
            <div style={inputDateGroup}>
              <label style={labelDate}>Hasta:</label>
              <input 
                type="date" 
                style={dateInput} 
                onChange={(e) => setFechasPublicacion({...fechasPublicacion, fin: e.target.value})}
              />
            </div>
          </div>
          <button 
            style={btnPublicarMaster} 
            onClick={handlePublicarTodo}
            disabled={publishing}
          >
            {publishing ? <Loader2 className="animate-spin" /> : <Send size={18}/>}
            Publicar Lote Completo
          </button>
        </div>
      )}

      {/* ... (Buscador y Listado) */}
      {/* Modifica la tarjeta del listado para mostrar si está publicado */}
      <div style={gridStyle}>
        {ofertasFiltradas.map(o => (
           <div key={o._id} style={itemCard}>
              <div style={cardHeader}>
                 <div style={o.publicado ? badgePublicado : badgePendiente}>
                    {o.publicado ? 'PUBLICADO' : 'BORRADOR'}
                 </div>
              </div>
              {/* ... contenido de la tarjeta */}
              {o.publicado && (
                <p style={{fontSize: '0.7rem', color: '#64748b', marginTop: '10px'}}>
                  Vigente hasta: {new Date(o.fechaFinOferta).toLocaleDateString()}
                </p>
              )}
           </div>
        ))}
      </div>
    </div>
  );
};

// --- NUEVOS ESTILOS PARA PUBLICAR ---
const publishBannerStyle = { 
    background: '#0f172a', color: 'white', padding: '20px 30px', borderRadius: '24px', 
    display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px',
    boxShadow: '0 15px 30px -10px rgba(15, 23, 42, 0.4)', border: '1px solid #1e293b'
};
const pendingBadge = { background: '#e67e22', padding: '5px 12px', borderRadius: '10px', fontSize: '0.8rem', fontWeight: '800' };
const inputDateGroup = { display: 'flex', flexDirection: 'column', gap: '4px' };
const labelDate = { fontSize: '0.7rem', color: '#94a3b8', fontWeight: '700', marginLeft: '5px' };
const dateInput = { background: '#1e293b', border: '1px solid #334155', color: 'white', padding: '8px', borderRadius: '10px', outline: 'none', fontSize: '0.9rem' };
const btnPublicarMaster = { background: '#10b981', color: 'white', border: 'none', padding: '12px 25px', borderRadius: '14px', cursor: 'pointer', fontWeight: '800', display: 'flex', alignItems: 'center', gap: '10px', transition: '0.3s' };
const badgePublicado = { background: '#d1fae5', color: '#065f46', padding: '4px 10px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: '800' };
const badgePendiente = { background: '#f1f5f9', color: '#64748b', padding: '4px 10px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: '800' };

export default GestionOfertas;
